class Solution:
    def solve(self, stalls: list[int], cows: int) -> int:
        stalls.sort()
        low, high = 0, stalls[-1] - stalls[0]
        def can_place(dist: int) -> bool:
            count = 1
            last = stalls[0]
            for pos in stalls[1:]:
                if pos - last >= dist:
                    count += 1
                    last = pos
                    if count >= cows:
                        return True
            return False
        ans = 0
        while low <= high:
            mid = (low + high) // 2
            if can_place(mid):
                ans = mid
                low = mid + 1
            else:
                high = mid - 1
        return ans

