#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(vector<int>& stalls, int cows) {
        sort(stalls.begin(), stalls.end());
        int low = 0;
        int high = stalls.back() - stalls.front();
        auto can_place = [&](int dist) {
            int count = 1;
            int last = stalls[0];
            for (size_t i = 1; i < stalls.size(); ++i) {
                if (stalls[i] - last >= dist) {
                    ++count;
                    last = stalls[i];
                    if (count >= cows) return true;
                }
            }
            return false;
        };
        int ans = 0;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (can_place(mid)) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    int cows;
    cin >> cows;
    int cnt;
    cin >> cnt; // equal to n
    vector<int> stalls(cnt);
    for (int i = 0; i < cnt; ++i) cin >> stalls[i];
    Solution sol;
    int result = sol.solve(stalls, cows);
    cout << result << "\n";
    return 0;
}
